var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"同時刻","ENG":"Meanwhile","TWN":"同一時間","SCN":"同一时间","DEU":"Meanwhile","FRA":"Meanwhile"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"으아아아아아아아……!","JPN":"うわああああああ……！","ENG":"Aaaaagh...!","TWN":"呃啊啊啊啊啊啊！"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"정신 차려, 꼬맹이!","JPN":"しっかりしろよ、おこちゃま！","ENG":"Get it together, kid!","TWN":"打起精神來，小鬼！"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"착지…! 착지해야 해! 꽉 잡으라고……!!","JPN":"着地……！　着地しないと！　しっかり捕まってろ……！！","ENG":"We're landing...! We've gotta land! Hold on tight...!!","TWN":"著陸！必須著陸！抓緊點！"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"하아아…! 그 망할 쥐돌이 자식……!","JPN":"はああ……！　あのクソネズミ野郎……！","ENG":"*Sigh...!* That damn rat-girl...!","TWN":"哈啊啊！那個該死的老鼠！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"싱글 다이빙인지, 뭔지 하더니… 하마터면 진짜 독신으로 죽을 뻔했잖아……?","JPN":"シングルダイビングはどうのこうの言ってたけど……一歩間違えば冗談じゃなく独身で死ぬところだったぞ……！","ENG":"Single dive? Yeah right... I almost died single for real...!","TWN":"說是單人躍入什麼的……差點真的單身到死了……？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"야, 꼬맹이! 너는 괜찮냐? 어디 까지거나, 부러진 데 없어?","JPN":"おい、おこちゃま！　大丈夫か？　擦りむいたり、折れたりしてないか？","ENG":"Hey, you okay, kid? Nothing twisted or broken?","TWN":"喂，小鬼！沒事吧？有沒有摔傷或者骨折？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"말도 마요. 라이카가 잡아줘서 겨우 살았어요.","JPN":"もうボロボロよ。ライカが捕まえてくれて助かったわ。","ENG":"Don't even ask. I barely survived thanks to you catching me.","TWN":"別提了，多虧了萊卡抓住我，我才活了下來。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"고마워요, 라이카.","JPN":"ありがとう、ライカ。","ENG":"Thanks, Laika.","TWN":"謝謝你，萊卡。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"알았으니까, 그럼 빨리 내려오기나 해. 무거워, 뚱냥아.","JPN":"わかったから早く降りろよ。重いんだよ、デブ猫。","ENG":"Yeah, yeah. Now get off already. You're heavy, chubcat.","TWN":"知道了，那就快點下來。好重啊，胖喵。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"뚱냥이!? 저 하나도 안 무겁거든요!?","JPN":"デブ猫！？　私のどこが重いっていうの！！","ENG":"Chubcat?! I am not heavy at all!","TWN":"胖喵！？我一點也不重啊！？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그나저나 일단 도착하긴 했는데…….","JPN":"それにしても、とりあえず到着はしたけど……","ENG":"Anyway, we made it...","TWN":"總之，到是到了……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"대체 여긴 어디야? 하늘이 시뻘건데? 원래 이면세계라는 게 다 이런 건가……?","JPN":"いったいどこだここ？　空真っ赤だし。裏世界って全部こうなのか……？","ENG":"Where are we? The sky's blood-red. Is this what the Counterside always looks like...?","TWN":"這到底是哪裡？天空怎麼是紅色的？原來異界就是這樣的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"뭐야, 그럼 라이카도 이게 첫 다이브인 거예요?","JPN":"なんだ、じゃあライカもこれが初ダイブなの？","ENG":"Huh? Is this is your first dive too, Laika?","TWN":"什麼？難道萊卡也是第一次躍入嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"꼬맹이. 어른이라고 뭐든 익숙할 거라고 여기는 건 착각이야.","JPN":"おこちゃま。大人ならなんでも慣れてると思うのは勘違いだぞ。","ENG":"Kid. Just because I'm an adult doesn't mean I've done everything.","TWN":"小鬼，別以為大人就都有經驗。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"누구든 처음은 있는 법이라고. 우주에는 가봤어도, 이면세계는 처음이야.","JPN":"誰にでも初めてはあるんだ。宇宙に行ったことはあるけど、裏世界は初めてだよ。","ENG":"Everyone has a first time. I've been to space, but not the Counterside.","TWN":"誰都有第一次嘛。雖然去過宇宙，但還是第一次去異界。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"근데 왜 지금까지 아무 말 안 했어요?","JPN":"どうして今まで黙ってたの？","ENG":"Then why didn't you say anything till now?","TWN":"那你為什麼到現在都沒說過呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"얌마! 네가 처음이라고 했는데, 나까지 처음이라고 하면 쪽팔리잖냐!","JPN":"おい！　あんたが初めてなんて言ってるのに、私まで実は同じなんだって言ったら恥ずかしいだろ！","ENG":"Come on! You said it was your first time, and if I said that too, how'd that make me look?!","TWN":"喂！你都說你是第一次了，如果我也說是第一次，那多丟臉啊！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"에휴, 하여간 어른답지 못하다니까.","JPN":"もう、全然大人らしくないんだから。","ENG":"*Sigh* So much for acting like an adult.","TWN":"唉，你真的很幼稚。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"역시 침식파 때문에 현실과 통신 연결은 안 되나…….","JPN":"やっぱり侵食波のせいで現実との通信は繋がらないのかな……","ENG":"Looks like we really can't connect to reality. It must be the Corruption ray blocking signals...","TWN":"果然因為侵蝕波，無法與現實進行通訊連接……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"어쨌든 박사님이 여기부턴 망원경이 길을 알려줄 거라고 했어요.","JPN":"とにかく博士が、ここからは望遠鏡が道案内をしてくれるって言ってたわ。","ENG":"Anyway, the doctor said the Telescope would guide us from here.","TWN":"不管怎麼說，博士說過從這裡開始望遠鏡會指引我們前進。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"Okay then...","TWN":"所以……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};